import type { AccountingPeriodGate } from './voucherToolbarActions';
import {
  canVoucherApprove,
  isAccountingPeriodLockedForDate,
} from './voucherToolbarActions';
import { isFinalProcessingLevel } from './voucherProcessingLevelDisplay';
import type { VoucherListRowActionsInput } from './voucherListRowActions';

export type VoucherBatchApproveRow = VoucherListRowActionsInput & {
  voucherDate?: string;
  entryDate?: string;
  invoiceDate?: string;
};

function resolveVoucherDate(row: VoucherBatchApproveRow): string | undefined {
  return row.voucherDate ?? row.entryDate ?? row.invoiceDate;
}

/** Dòng đủ điều kiện đổi mức xử lý batch — parity form `canVoucherApprove` + Posted chỉ hạ mức. */
export function canBatchApproveVoucherRow(
  row: VoucherBatchApproveRow,
  targetLevel: string,
  options: { canUnpost: boolean; periods?: AccountingPeriodGate[] },
): boolean {
  const target = String(targetLevel ?? '').trim();
  const current = String(row.processingLevel ?? '').trim();
  if (!target || target === current) return false;
  if (row.status === 'Cancelled') return false;

  const isPosted = row.status === 'Posted';
  const isDowngrade =
    Number(target) < Number(current) ||
    (isFinalProcessingLevel(current) && !isFinalProcessingLevel(target));

  if (isPosted) {
    if (!isDowngrade || !options.canUnpost) return false;
    const voucherDate = resolveVoucherDate(row);
    if (
      voucherDate &&
      options.periods?.length &&
      isAccountingPeriodLockedForDate(voucherDate, options.periods)
    ) {
      return false;
    }
    return canVoucherApprove({
      isNew: false,
      status: row.status,
      processingLevel: row.processingLevel,
      voucherDate: voucherDate ?? '',
      periods: options.periods ?? [],
      targetLevel: target,
    });
  }

  if (row.status !== 'Draft') return false;

  const voucherDate = resolveVoucherDate(row);
  return canVoucherApprove({
    isNew: false,
    status: row.status,
    processingLevel: row.processingLevel,
    voucherDate: voucherDate ?? '',
    periods: options.periods ?? [],
    targetLevel: target,
  });
}

export function voucherBatchApproveSkippedMessage(skipped: number, total: number): string {
  if (skipped <= 0) return '';
  if (skipped === total) {
    return 'Không có chứng từ nào đủ điều kiện phê duyệt với mức xử lý đã chọn';
  }
  return `Bỏ qua ${skipped} chứng từ không đủ điều kiện — chỉ phê duyệt các phiếu hợp lệ`;
}
