import React from 'react';
import {
  ErpDataListGrid,
  catalogListTableConfigFromSchema,
  type ErpDataListGridProps,
} from '@linm-soft-org/linm-web-common-components';
import erp from '../../styles/erpPage.module.css';
import type { CatalogUiField, CatalogUiSchema } from '../../types/catalogUiSchema';
import type { UseVoucherListSelectionResult } from '../../hooks/useVoucherListSelection';
import { ListSchemaCell } from './ListSchemaCell';

export interface CatalogListGridFromSchemaProps<T extends { id: string }> {
  testIdPrefix: string;
  rows: T[];
  page: number;
  pageSize: number;
  columns: CatalogUiField[];
  schema?: CatalogUiSchema | null;
  selection: UseVoucherListSelectionResult<T>;
  getRowId: (row: T) => string;
  /** @deprecated Mặc định mọi dòng chọn được — lọc ở action batch. */
  isRowSelectable?: (row: T) => boolean;
  getRowSelectDisabledReason?: (row: T) => string | undefined;
  formatProcessingLevel?: (level: string) => string;
  gridProps?: Pick<
    ErpDataListGridProps<T>,
    | 'onRowOpenActionMenu'
    | 'rowMenuHintMessage'
    | 'rowMenuHintDismissStorageKey'
    | 'enableRowMenuLongPress'
    | 'onRowDoubleClick'
  >;
}

export function CatalogListGridFromSchema<T extends { id: string }>({
  testIdPrefix,
  rows,
  page,
  pageSize,
  columns,
  schema,
  selection,
  getRowId,
  isRowSelectable,
  getRowSelectDisabledReason,
  formatProcessingLevel,
  gridProps,
}: CatalogListGridFromSchemaProps<T>): React.ReactElement {
  const columnDefs = columns.map(col => ({
    key: col.key,
    label: col.label,
    width: col.list?.width,
  }));

  const tableConfig = {
    ...catalogListTableConfigFromSchema(schema?.list),
    resizable: schema?.list?.resizableColumns ?? false,
  };

  return (
    <ErpDataListGrid
      testIdPrefix={testIdPrefix}
      rows={rows}
      page={page}
      pageSize={pageSize}
      selection={selection}
      getRowId={getRowId}
      isRowSelectable={isRowSelectable}
      getRowSelectDisabledReason={getRowSelectDisabledReason}
      columnDefs={columnDefs}
      tableConfig={tableConfig}
      headerCells={(
        <>
          {columns.map(col => (
            <th
              key={col.key}
              className={col.format === 'vnd' || col.key === 'amount' || col.key === 'totalAmount' ? erp.colAmount : undefined}
            >
              {col.label}
            </th>
          ))}
        </>
      )}
      renderRow={row => (
        <>
          {columns.map(col => (
            <ListSchemaCell
              key={col.key}
              field={col}
              row={row as unknown as Record<string, unknown>}
              testIdPrefix={testIdPrefix}
              formatProcessingLevel={formatProcessingLevel}
            />
          ))}
        </>
      )}
      {...gridProps}
    />
  );
}
